// ======================================================================
// Threat Intelligence (TI) Mapping: IP Indicators → SigninLogs
// ======================================================================
// Lookback windows:
// dt_lookBack = how far back to search SigninLogs
// ioc_lookBack = how far back to search TI indicators
let dt_lookBack = 1h;
let ioc_lookBack = 14d;
// ======================================================================
// STEP 1: Define a reusable function for both SigninLogs and AADNonInteractive logs
// The function accepts a table name and performs TI-IP correlation
// ======================================================================
let aadFunc = (tableName:string) {
    // --------------------------------------------------------------
    // STEP 1A: Build IP Indicators from ThreatIntelIndicators
    // --------------------------------------------------------------
    let IP_Indicators =
        ThreatIntelIndicators
        | where TimeGenerated >= ago(ioc_lookBack)                // Recent indicators
        | where IsActive == true                                  // Must be active
        | where IsDeleted == false                                // Exclude deleted
        | where coalesce(Revoked, false) == false                 // Exclude revoked
        | where ValidUntil > now()                                // Must not be expired
        | where Confidence >= 70                                  // Only high-confidence IoCs
        // Extract IP-related observable fields
        | extend
            NetworkIP = iff(ObservableKey == "ipv4-addr:value", ObservableValue, ""),
            NetworkSourceIP = iff(ObservableKey == "network-traffic:src_ref.value", ObservableValue, ""),
            NetworkDestinationIP = iff(ObservableKey == "network-traffic:dst_ref.value", ObservableValue, "")
        // Keep only indicators with at least one valid IP field
        | where isnotempty(NetworkIP) 
            or isnotempty(NetworkDestinationIP) 
            or isnotempty(NetworkSourceIP)
        // Normalize TI_ipEntity to a single IP value
        | extend TI_ipEntity = iff(isnotempty(NetworkIP), NetworkIP, NetworkDestinationIP)
        | extend TI_ipEntity = iff(isempty(TI_ipEntity) and isnotempty(NetworkSourceIP), NetworkSourceIP, TI_ipEntity)
        | where isnotempty(TI_ipEntity)
        // Keep the latest version of each indicator
        | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) by Id, TI_ipEntity
        // Add metadata fields for output
        | extend
            IndicatorId = tostring(Data.id),
            Description = tostring(Data.description),
            ActivityGroupNames = tostring(Data.labels),
            ThreatType = tostring(Data.indicator_types[0]),
            Url = iff(ObservableKey == "url:value", ObservableValue, tostring(Data.external_references[0].url)),
            ExpirationDateTime = ValidUntil,
            ConfidenceScore = toreal(Confidence);
    // --------------------------------------------------------------
    // STEP 1B: Join IP Indicators with the selected AAD sign-in table
    // --------------------------------------------------------------
    IP_Indicators
    | join kind=innerunique (
        table(tableName)
        | where TimeGenerated >= ago(dt_lookBack)                // Recent sign-in activity
        | extend Status = todynamic(Status), 
                 LocationDetails = todynamic(LocationDetails)
        // Extract status fields
        | extend
            StatusCode = tostring(Status.errorCode),
            StatusDetails = tostring(Status.additionalDetails),
            StatusReason = tostring(Status.failureReason)
        // Extract location fields
        | extend
            State = tostring(LocationDetails.state),
            City = tostring(LocationDetails.city),
            Region = tostring(LocationDetails.countryOrRegion)
        | extend
            SigninLogs_TimeGenerated = TimeGenerated,
            Type = Type
    ) on $left.TI_ipEntity == $right.IPAddress                   // Match TI IP to sign-in IP
    // Only keep sign-ins that occurred before the IoC expired
    | where SigninLogs_TimeGenerated < ExpirationDateTime
    // Keep the latest matching sign-in per indicator
    | summarize SigninLogs_TimeGenerated = arg_max(SigninLogs_TimeGenerated, *) 
        by IndicatorId, IPAddress
    // Select final output fields
    | project
        SigninLogs_TimeGenerated,
        Description,
        ActivityGroupNames,
        IndicatorId,
        ThreatType,
        Url,
        ExpirationDateTime,
        ConfidenceScore,
        TI_ipEntity,
        IPAddress,
        UserPrincipalName,
        AppDisplayName,
        StatusCode,
        StatusDetails,
        StatusReason,
        NetworkIP,
        NetworkDestinationIP,
        NetworkSourceIP,
        Type
    // Add normalized fields for analytics
    | extend
        timestamp = SigninLogs_TimeGenerated,
        Name = tostring(split(UserPrincipalName, "@", 0)[0]),
        UPNSuffix = tostring(split(UserPrincipalName, "@", 1)[0]);
};
// ======================================================================
// STEP 2: Run the function for both interactive and non-interactive sign-ins
// ======================================================================
let aadSignin = aadFunc("SigninLogs");
let aadNonInt = aadFunc("AADNonInteractiveUserSignInLogs");
// ======================================================================
// STEP 3: Combine both datasets
// ======================================================================
union isfuzzy=true aadSignin, aadNonInt

