// ======================================================================
// Threat Intelligence (TI) Mapping: IP Indicators → Azure Key Vault Logs
// ======================================================================
// Lookback windows:
// dt_lookBack = how far back to search Key Vault diagnostic logs
// ioc_lookBack = how far back to search TI indicators
let dt_lookBack = 1h;
let ioc_lookBack = 14d;
// ======================================================================
// STEP 1: Load Rapid Release TI (CSV-based IoC feed)
// Provides additional TI indicators outside the ThreatIntelIndicators table.
// ======================================================================
let IoCList = materialize(
    externaldata(
        TimeGenerated:datetime,
        IoC:string,
        IoC_Type:string,
        ExpirationDateTime:datetime,
        Description:string,
        Action:string,
        ConfidenceScore:real,
        ThreatType:string,
        Active:string,
        Type:string,
        TrafficLightProtocolLevel:string,
        ActivityGroupNames:string
    )[@'https://raw.githubusercontent.com/microsoft/mstic/master/RapidReleaseTI/Indicators.csv']
    with(format="csv", ignoreFirstRecord=True)
);
// ======================================================================
// STEP 2: Extract Key Vault access events with valid IP addresses
// ======================================================================
let KeyVaultEvents_ =
    AzureDiagnostics
    | where TimeGenerated >= ago(dt_lookBack)                     // Recent events only
    | where ResourceType =~ "VAULTS"                              // Only Key Vault logs
    | where isnotempty(CallerIPAddress)                           // Must contain an IP
    | extend
        KeyVaultEvents_TimeGenerated = TimeGenerated,
        ClientIP = tostring(CallerIPAddress);
// Extract unique IPs seen in Key Vault logs
let KeyVaultIPs =
    KeyVaultEvents_
    | distinct ClientIP;
// ======================================================================
// STEP 3: Build IP Indicators from TI table + Rapid Release feed
// Combines authoritative TI with Rapid Release IoCs.
// ======================================================================
let IP_Indicators =
    materialize(
        union isfuzzy=true
        // --- Source 1: ThreatIntelIndicators table ---
        (
            ThreatIntelIndicators
            | where TimeGenerated >= ago(ioc_lookBack)
            | where IsActive == true
            | where IsDeleted == false
            | where coalesce(Revoked, false) == false
            | where ValidUntil > now()
            | where Confidence >= 70
              // Extract IP-related observable fields
            | extend
                NetworkIP = iff(ObservableKey == "ipv4-addr:value" or ObservableKey == "ipv6-addr:value", ObservableValue, ""),
                NetworkSourceIP = iff(ObservableKey == "network-traffic:src_ref.value", ObservableValue, ""),
                NetworkDestinationIP = iff(ObservableKey == "network-traffic:dst_ref.value", ObservableValue, "")
              // Keep only indicators with at least one valid IP field
            | where isnotempty(NetworkIP) or isnotempty(NetworkDestinationIP) or isnotempty(NetworkSourceIP)
              // Normalize TI_ipEntity to a single IP value
            | extend TI_ipEntity = iff(isnotempty(NetworkIP), NetworkIP, NetworkDestinationIP)
            | extend TI_ipEntity = iff(isempty(TI_ipEntity) and isnotempty(NetworkSourceIP), NetworkSourceIP, TI_ipEntity)
            | where isnotempty(TI_ipEntity)
              // Exclude private, link-local, loopback, and unspecified IPs
            | where ipv4_is_private(TI_ipEntity) == false
              and TI_ipEntity !startswith "fe80"
              and TI_ipEntity !startswith "::"
              and TI_ipEntity !startswith "127."
              // Keep only IoCs that appear in Key Vault logs
            | join kind=innerunique KeyVaultIPs 
                on $left.TI_ipEntity == $right.ClientIP
              // Keep latest version of each indicator
            | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) 
                by Id, TI_ipEntity
              // Add metadata fields for output
            | extend
                IndicatorId = tostring(Data.id),
                Description = tostring(Data.description),
                ActivityGroupNames = tostring(Data.labels),
                ThreatType = tostring(Data.indicator_types[0]),
                Url = tostring(Data.external_references[0].url),
                ExpirationDateTime = ValidUntil,
                ConfidenceScore = toreal(Confidence),
                Type = tostring(Data.type),
                TrafficLightProtocolLevel = tostring(AdditionalFields.TLPLevel),
                IoC = TI_ipEntity,
                EmailSourceIpAddress = ""
        ),
        // --- Source 2: Rapid Release TI (CSV feed) ---
        (
            IoCList
            | where IoC_Type =~ "IP"                              // Only IP IoCs
            | where ExpirationDateTime > now()                    // Must not be expired
            | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) by IoC
            | where Active =~ "True"                              // Only active IoCs
            | extend
                TI_ipEntity = IoC,
                IndicatorId = strcat("MSTIC-RapidRelease-", IoC), // Synthetic ID for CSV IoCs
                Url = "",
                NetworkIP = IoC,
                NetworkDestinationIP = "",
                NetworkSourceIP = "",
                EmailSourceIpAddress = ""
            | project-away IoC_Type
        )
    );
// ======================================================================
// STEP 4: Join IP Indicators with Key Vault logs
// ======================================================================
IP_Indicators
| join kind=innerunique KeyVaultEvents_ 
    on $left.TI_ipEntity == $right.ClientIP                     // Match TI IP to Key Vault caller IP
// Only keep events that occurred before the IoC expired
| where KeyVaultEvents_TimeGenerated < ExpirationDateTime
// ======================================================================
// STEP 5: Summarize and output final enriched results
// ======================================================================
| summarize KeyVaultEvents_TimeGenerated = arg_max(KeyVaultEvents_TimeGenerated, *) 
    by IndicatorId, ClientIP, IoC
| project
    KeyVaultEvents_TimeGenerated,
    Description,
    ActivityGroupNames,
    IndicatorId,
    ThreatType,
    Url,
    ExpirationDateTime,
    ConfidenceScore,
    TI_ipEntity,
    ClientIP,
    ResourceId,
    SubscriptionId,
    OperationName,
    ResultType,
    CorrelationId,
    id_s,
    clientInfo_s,
    httpStatusCode_d,
    identity_claim_appid_g,
    identity_claim_http_schemas_microsoft_com_identity_claims_objectidentifier_g,
    NetworkIP,
    NetworkDestinationIP,
    NetworkSourceIP,
    EmailSourceIpAddress,
    Type
// Add normalized timestamp field
| extend timestamp = KeyVaultEvents_TimeGenerated;

