    )[@'https://raw.githubusercontent.com/microsoft/mstic/master/RapidReleaseTI/Indicators.csv']
    with(format="csv", ignoreFirstRecord=True)
);
// ======================================================================
// STEP 2: Extract IP addresses from AzureActivity logs
// ======================================================================
let AzureActivity_ =
    AzureActivity
    | where TimeGenerated >= ago(dt_lookBack)                     // Recent activity only
    | where isnotempty(CallerIpAddress)                           // Must contain an IP
    | extend AzureActivity_TimeGenerated = TimeGenerated;
// Extract unique IPs seen in AzureActivity
let AzureActivityIPs =
    AzureActivity_
    | distinct CallerIpAddress;
// ======================================================================
// STEP 3: Build IP Indicators from TI sources (TI table + RapidRelease CSV)
// ======================================================================
let IP_Indicators =
    materialize(
        union isfuzzy=true
        // --- Source 1: ThreatIntelIndicators table ---
        (
            ThreatIntelIndicators
            | where TimeGenerated >= ago(ioc_lookBack)            // Recent indicators
            | where IsActive == true                              // Must be active
            | where IsDeleted == false                            // Exclude deleted
            | where coalesce(Revoked, false) == false             // Exclude revoked
            | where ValidUntil > now()                            // Must not be expired
            | where Confidence >= 70                              // Only high-confidence IoCs
            | where ObservableKey in~ ("ipv4-addr:value", "ipv6-addr:value")
            | extend TI_ipEntity = tostring(ObservableValue)      // Extract IP value
            | where isnotempty(TI_ipEntity)
              // Exclude private, link-local, loopback, and unspecified IPs
            | where ipv4_is_private(TI_ipEntity) == false
              and TI_ipEntity !startswith "fe80"
              and TI_ipEntity !startswith "::"
              and TI_ipEntity !startswith "127."
            // Keep only IoCs that appear in AzureActivity logs
            | join kind=innerunique AzureActivityIPs 
                on $left.TI_ipEntity == $right.CallerIpAddress
            // Add metadata fields for output
            | extend
                IndicatorId = tostring(Data.id),
                Description = tostring(Data.description),
                ActivityGroupNames = tostring(Data.labels),
                ThreatType = tostring(Data.indicator_types[0]),
                Url = tostring(Data.external_references[0].url),
                ExpirationDateTime = ValidUntil,
                ConfidenceScore = toreal(Confidence),
                Type = tostring(Data.type),
                TrafficLightProtocolLevel = tostring(AdditionalFields.TLPLevel),
                // Normalized fields for downstream analytics
                IoC = TI_ipEntity,
                NetworkIP = TI_ipEntity,
                NetworkDestinationIP = "",
                NetworkSourceIP = "",
                EmailSourceIpAddress = ""
            // Keep latest version of each indicator
            | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) 
                by IndicatorId, IoC
        ),
        // --- Source 2: Rapid Release TI (CSV feed) ---
        (
            IoCList
            | where IoC_Type =~ "IP"                              // Only IP IoCs
            | where ExpirationDateTime > now()                    // Must not be expired
            | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) by IoC
            | where Active =~ "True"                              // Only active IoCs
            | extend
                TI_ipEntity = IoC,
                IndicatorId = strcat("MSTIC-RapidRelease-", IoC), // Synthetic ID for CSV IoCs
                Url = "",
                NetworkIP = IoC,
                NetworkDestinationIP = "",
                NetworkSourceIP = "",
                EmailSourceIpAddress = ""
            | project-away IoC_Type
        )
    );
// ======================================================================
// STEP 4: Join IP Indicators with AzureActivity logs
// ======================================================================
IP_Indicators
| join kind=innerunique AzureActivity_ 
    on $left.TI_ipEntity == $right.CallerIpAddress               // Match TI IP to activity IP
// Only keep AzureActivity events that occurred before the IoC expired
| where AzureActivity_TimeGenerated < ExpirationDateTime
// ======================================================================
// STEP 5: Summarize and output final enriched results
// ======================================================================
| summarize AzureActivity_TimeGenerated = arg_max(AzureActivity_TimeGenerated, *) 
    by IndicatorId, CallerIpAddress, IoC
| project
    AzureActivity_TimeGenerated,
    Description,
    ActivityGroupNames,
    IndicatorId,
    ThreatType,
    Url,
    ExpirationDateTime,
    ConfidenceScore,
    TI_ipEntity,
    CallerIpAddress,
    Caller,
    OperationNameValue,
    ActivityStatusValue,
    CategoryValue,
    ResourceId,
    NetworkIP,
    NetworkDestinationIP,
    NetworkSourceIP,
    EmailSourceIpAddress,
    Type
