// ======================================================================
// Threat Intelligence (TI) Mapping: Domain Indicators → EmailEvents
// ======================================================================
// Lookback windows:
// dt_lookBack = how far back to search EmailEvents
// ioc_lookBack = how far back to search TI indicators
let dt_lookBack = 1h;
let ioc_lookBack = 14d;
// ======================================================================
// STEP 1: Collect EmailEvents with valid sender/recipient domains
// ======================================================================
let EmailEvents_ = materialize(
    EmailEvents
    | where TimeGenerated >= ago(dt_lookBack)                     // Recent email activity
    | where isnotempty(RecipientEmailAddress)                     // Must have a recipient
    | where isnotempty(SenderFromAddress)                         // Must have a sender
    | where DeliveryAction !has "Blocked"                         // Exclude blocked emails
    | project-rename EmailEvents_TimeGenerated = TimeGenerated
    | extend
        SenderFromDomain = tolower(SenderFromDomain),             // Normalize sender domain
        RecipientEmailDomain = tolower(tostring(split(RecipientEmailAddress, "@", 1))) // Extract recipient domain
);
// ======================================================================
// STEP 2: Extract all unique domains seen in EmailEvents
// Includes both sender and recipient domains
// ======================================================================
let RelevantDomains = materialize(
    union
        (EmailEvents_ | distinct Domain = SenderFromDomain),
        (EmailEvents_ | distinct Domain = RecipientEmailDomain)
    | where isnotempty(Domain)
    | distinct Domain
);
// ======================================================================
// STEP 3: Pull TI Domain Indicators and match them to observed domains
// ======================================================================
let TI = materialize(
    ThreatIntelIndicators
    | where TimeGenerated >= ago(ioc_lookBack)                    // Recent indicators
    | where IsActive == true                                      // Must be active
    | where IsDeleted == false                                    // Exclude deleted indicators
    | where coalesce(Revoked, false) == false                     // Exclude revoked indicators
    | where ValidUntil > now()                                    // Must not be expired
    | where ObservableKey =~ "domain-name:value"                  // Only domain indicators
    | extend
        TI_Domain = tolower(ObservableValue),                     // Normalize domain
        DomainName = ObservableValue,
        IndicatorId = tostring(Data.id),
        Description = tostring(Data.description),
        ThreatType = tostring(Data.indicator_types[0]),
        ActivityGroupNames = tostring(Data.labels),
        ConfidenceScore = toint(Confidence),
        ExpirationDateTime = ValidUntil,
        TrafficLightProtocolLevel = tostring(AdditionalFields.TLPLevel),
        Url = iff(ObservableKey == "url:value", ObservableValue, "") // Only populate URL when applicable
    | where isnotempty(TI_Domain)
    | join kind=innerunique RelevantDomains 
        on $left.TI_Domain == $right.Domain                       // Keep only TI domains seen in email events
    | where Description !contains_cs "State: inactive;"           // Filter out inactive indicators
      and Description !contains_cs "State: falsepos;"             // Filter out false positives
    | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) 
        by IndicatorId, TI_Domain                                 // Keep latest version of each indicator
);
// ======================================================================
// STEP 4: Join TI Indicators with EmailEvents
// Match TI domain to both sender and recipient domains
// ======================================================================
(
    union
        (TI | join kind=innerunique EmailEvents_ 
            on $left.TI_Domain == $right.SenderFromDomain),
        (TI | join kind=innerunique EmailEvents_ 
            on $left.TI_Domain == $right.RecipientEmailDomain)
)
| where EmailEvents_TimeGenerated < ExpirationDateTime            // Ensure event occurred before TI expired
// ======================================================================
// STEP 5: Summarize and output final enriched results
// ======================================================================
| summarize EmailEvents_TimeGenerated = arg_max(EmailEvents_TimeGenerated, *) 
    by IndicatorId, RecipientEmailAddress
| project
    EmailEvents_TimeGenerated,
    Description,
    ActivityGroupNames,
    IndicatorId,
    ThreatType,
    ExpirationDateTime,
    ConfidenceScore,
    DomainName,
    RecipientEmailAddress,
    SenderFromAddress,
    Subject,
    ConfidenceLevel,
    Url,
    Type,
    TI_Domain,
    TrafficLightProtocolLevel,
    DeliveryAction,
    DeliveryLocation,
    EmailDirection,
    Pattern,
    ObservableKey,
    ObservableValue
| extend
    Name = tostring(split(RecipientEmailAddress, "@", 0)[0]),     // Extract username
    UPNSuffix = tostring(split(RecipientEmailAddress, "@", 1)[0]),// Extract domain
    timestamp = EmailEvents_TimeGenerated;

// ======================================================================
// Threat Intelligence (TI) Mapping: Domain Indicators → DeviceNetworkEvents
// ======================================================================
// Lookback windows:
// dt_lookBack = how far back to search DeviceNetworkEvents
// ioc_lookBack = how far back to search TI indicators
let dt_lookBack = 1h;
let ioc_lookBack = 14d;
// ======================================================================
// STEP 1: Collect DeviceNetworkEvents with valid RemoteUrl values
// ======================================================================
let DeviceNetworkEvents_ =
    DeviceNetworkEvents
    | where TimeGenerated >= ago(dt_lookBack)                 // Only recent events
    | where isnotempty(RemoteUrl)                             // Must contain a URL
    | where ActionType !has "ConnectionFailed"                // Exclude failed connections
    | extend Domain = tostring(parse_url(tolower(RemoteUrl)).Host)  // Extract domain from URL
    | where isnotempty(Domain)                                // Only keep valid domains
    | project-rename DeviceNetworkEvents_TimeGenerated = TimeGenerated;
// Extract unique domains seen in DeviceNetworkEvents
let DeviceNetworkEventDomains =
    DeviceNetworkEvents_
    | distinct Domain;
// ======================================================================
// STEP 2: Pull TI Domain Indicators and match them to observed domains
// ======================================================================
let TI_Domain_Indicators =
    ThreatIntelIndicators
    | where TimeGenerated >= ago(ioc_lookBack)                // Only recent indicators
    | where IsActive == true                                  // Must be active
    | where IsDeleted == false                                // Exclude deleted indicators
    | where coalesce(Revoked, false) == false                 // Exclude revoked indicators
    | where ValidUntil > now()                                // Must not be expired
    | where ObservableKey =~ "domain-name:value"              // Only domain indicators
    | extend TI_Domain = tolower(ObservableValue)             // Normalize domain
    | where isnotempty(TI_Domain)
    | join kind=innerunique DeviceNetworkEventDomains 
        on $left.TI_Domain == $right.Domain                   // Keep only TI domains seen in events
    | extend
        IndicatorId = tostring(Data.id),
        Description = tostring(Data.description),
        ThreatType = tostring(Data.indicator_types[0]),
        ConfidenceScore = toint(Confidence),
        ExpirationDateTime = ValidUntil,
        TrafficLightProtocolLevel = tostring(AdditionalFields.TLPLevel)
    | where Description !contains_cs "State: inactive;"        // Filter out inactive indicators
      and Description !contains_cs "State: falsepos;"          // Filter out false positives
    | summarize LatestIndicatorTime = arg_max(TimeGenerated, *) 
        by IndicatorId, TI_Domain;                             // Keep latest version of each indicator
// ======================================================================
// STEP 3: Join TI Indicators with DeviceNetworkEvents
// ======================================================================
TI_Domain_Indicators
| join kind=innerunique DeviceNetworkEvents_ 
    on $left.TI_Domain == $right.Domain                       // Match TI domain to event domain
| where DeviceNetworkEvents_TimeGenerated < ExpirationDateTime // Ensure event occurred before TI expired
// ======================================================================
// STEP 4: Summarize and output final enriched results
// ======================================================================
| summarize DeviceNetworkEvents_TimeGenerated = arg_max(DeviceNetworkEvents_TimeGenerated, *) 
    by IndicatorId, TI_Domain
| project
    DeviceNetworkEvents_TimeGenerated,
    IndicatorId,
    TI_Domain,
    Url = RemoteUrl,
    ConfidenceScore,
    Description,
    ThreatType,
    Tags,
    TrafficLightProtocolLevel,
    ActionType,
    DeviceId,
    DeviceName,
    InitiatingProcessAccountUpn,
    InitiatingProcessCommandLine,
    RemoteIP,
    RemotePort,
    Pattern,
    ObservableKey,
    ObservableValue
| extend
    Name = tostring(split(InitiatingProcessAccountUpn, '@', 0)[0]),  // Extract username
    UPNSuffix = tostring(split(InitiatingProcessAccountUpn, '@', 1)[0]), // Extract domain
    timestamp = DeviceNetworkEvents_TimeGenerated,
    UserPrincipalName = InitiatingProcessAccountUpn;

